'use strict';

/**
 * Sliding Window Rate Limiter for Express.js
 *
 * TRUE sliding window: every individual request timestamp is recorded, and on
 * each incoming request all timestamps older than `windowMs` (relative to NOW)
 * are evicted before counting. There is no fixed bucket that resets on a clock
 * boundary — the window continuously slides with the current time.
 *
 * @param {Object}   [options]
 * @param {number}   [options.windowMs=60000]   Window size in milliseconds.
 * @param {number}   [options.maxRequests=100]  Max requests per window per IP.
 * @param {number}   [options.cleanupMs=60000]  How often the stale-entry sweep runs.
 * @param {Function} [options.keyGenerator]     (req) => string. Defaults to req.ip.
 * @returns {Function} Express middleware with a `.close()` method to clear the
 *                     cleanup timer so it won't keep the process alive.
 */
function createRateLimiter(options = {}) {
  const {
    windowMs = 60000,
    maxRequests = 100,
    cleanupMs = 60000,
    keyGenerator = (req) => req.ip,
  } = options;

  if (!Number.isFinite(windowMs) || windowMs <= 0) {
    throw new TypeError('windowMs must be a positive number');
  }
  if (!Number.isFinite(maxRequests) || maxRequests <= 0) {
    throw new TypeError('maxRequests must be a positive number');
  }

  // Map<clientKey, number[]> — value is an array of request timestamps (ms).
  const hits = new Map();

  /**
   * Drop timestamps outside the sliding window. Timestamps are appended in
   * chronological order, so expired entries are always a contiguous prefix —
   * find the first index still inside the window and slice once.
   */
  function prune(timestamps, windowStart) {
    let i = 0;
    while (i < timestamps.length && timestamps[i] <= windowStart) {
      i++;
    }
    return i === 0 ? timestamps : timestamps.slice(i);
  }

  const middleware = function rateLimiter(req, res, next) {
    const now = Date.now();
    const windowStart = now - windowMs; // anything <= this is expired
    const key = keyGenerator(req);

    // Evict everything older than the window BEFORE counting.
    let timestamps = prune(hits.get(key) || [], windowStart);

    if (timestamps.length >= maxRequests) {
      // Over the limit. A slot frees when the OLDEST in-window request ages
      // out, i.e. at timestamps[0] + windowMs.
      const resetMs = timestamps[0] + windowMs;
      const retryAfterSec = Math.max(1, Math.ceil((resetMs - now) / 1000));

      hits.set(key, timestamps); // persist the pruned array

      res.setHeader('X-RateLimit-Limit', maxRequests);
      res.setHeader('X-RateLimit-Remaining', 0);
      res.setHeader('X-RateLimit-Reset', Math.ceil(resetMs / 1000));
      res.setHeader('Retry-After', retryAfterSec);

      res.status(429).json({
        error: 'Rate limit exceeded',
        retryAfter: retryAfterSec,
      });
      return; // Do NOT call next().
    }

    // Under the limit — record this request and allow it through.
    timestamps.push(now);
    hits.set(key, timestamps);

    const remaining = maxRequests - timestamps.length;
    const resetMs = timestamps[0] + windowMs; // when the oldest in-window req expires

    res.setHeader('X-RateLimit-Limit', maxRequests);
    res.setHeader('X-RateLimit-Remaining', Math.max(0, remaining));
    res.setHeader('X-RateLimit-Reset', Math.ceil(resetMs / 1000));

    next();
  };

  // ---- Memory management: periodic sweep of fully-expired IP entries ----
  const cleanupTimer = setInterval(() => {
    const windowStart = Date.now() - windowMs;
    for (const [key, timestamps] of hits) {
      const pruned = prune(timestamps, windowStart);
      if (pruned.length === 0) {
        hits.delete(key); // no activity within the window — reclaim memory
      } else if (pruned.length !== timestamps.length) {
        hits.set(key, pruned);
      }
    }
  }, cleanupMs);

  // Don't let the cleanup timer hold the event loop open on its own.
  if (typeof cleanupTimer.unref === 'function') {
    cleanupTimer.unref();
  }

  /**
   * Stop the cleanup interval. Call on graceful shutdown (or in tests) so the
   * timer is cleared and won't keep the process alive.
   */
  middleware.close = function close() {
    clearInterval(cleanupTimer);
    hits.clear();
  };

  return middleware;
}

module.exports = createRateLimiter;
module.exports.createRateLimiter = createRateLimiter;
```

## Usage example

```js
const express = require('express');
const createRateLimiter = require('./rate-limiter');

const app = express();

// IMPORTANT: req.ip behind a proxy.
// By default Express reports the IP of the immediate TCP peer. If your app runs
// behind a reverse proxy / load balancer (Nginx, Cloudflare, an ELB, etc.),
// that peer is the proxy — so EVERY client would share one bucket. Enable
// trust proxy so Express derives req.ip from the X-Forwarded-For header:
//
//   app.set('trust proxy', 1);        // trust the first hop (e.g. one Nginx)
//   app.set('trust proxy', true);     // trust all hops (only if XFF is sanitized)
//
// Only trust proxies you actually control — clients can spoof X-Forwarded-For,
// and a wide-open setting lets them forge IPs and dodge the limit.
app.set('trust proxy', 1);

const limiter = createRateLimiter({
  windowMs: 60_000,   // 1 minute
  maxRequests: 100,   // 100 requests per IP per sliding minute
});

app.use(limiter);

app.get('/', (req, res) => res.send('ok'));

const server = app.listen(3000, () => console.log('listening on :3000'));

// Graceful shutdown — clear the cleanup timer.
process.on('SIGTERM', () => {
  limiter.close();
  server.close();
});
```

### Key design notes

- **True sliding window** — each request stores its own timestamp; `prune()` evicts everything older than `now - windowMs` on every call, then counts. No fixed-interval reset boundary, so a client can't burst `2×maxRequests` across a boundary the way fixed-window limiters allow.
- **Eviction order** — timestamps are appended chronologically, so expired entries are always a contiguous prefix and a single `slice` removes them.
- **`X-RateLimit-Reset` / `Retry-After`** are computed from `timestamps[0] + windowMs` (when the oldest in-window request ages out), which is the exact moment a slot frees — not a wall-clock boundary.
- **Memory** — the `unref`'d cleanup interval drops IPs with no in-window activity; `close()` clears it so the timer never keeps the process alive (important for tests and clean shutdown).
- **Scope** — this is per-process in-memory state. Across multiple workers/instances you'd want a shared store (e.g. Redis with a sorted set per key) to enforce a global limit.

