/**
 * rateLimiter.js
 *
 * True sliding-window rate-limiting middleware for Express.js.
 *
 * Unlike a fixed-window limiter (which resets a counter at regular clock
 * boundaries), this records the exact timestamp of every accepted request and
 * discards timestamps that have slid out of the window before deciding whether
 * to allow or reject the next one.
 *
 * ─── PROXY NOTE ─────────────────────────────────────────────────────────────
 * Express populates `req.ip` from the socket address by default.  When your
 * app sits behind a reverse proxy (Nginx, AWS ALB, Cloudflare…) the socket
 * peer is always the proxy's IP, so every client appears to share the same
 * address and they all hit the same bucket.
 *
 * Fix this before attaching the middleware:
 *
 *   app.set('trust proxy', 1);          // trust the first hop (e.g. local Nginx)
 *   app.set('trust proxy', 'loopback'); // same effect, named alias
 *
 * With trust proxy enabled, Express reads X-Forwarded-For and sets req.ip to
 * the real client IP.
 * See: https://expressjs.com/en/guide/behind-proxies.html
 * ────────────────────────────────────────────────────────────────────────────
 */

'use strict';

/**
 * @typedef {Object} RateLimiterOptions
 * @property {number} [windowMs=60000]   Sliding window size in milliseconds.
 * @property {number} [maxRequests=100]  Maximum requests allowed per window.
 */

/**
 * @typedef {Object} RateLimiter
 * @property {Function} middleware  Express middleware (req, res, next) => void.
 * @property {Function} close       Cancels the background cleanup timer so the
 *                                  process can exit cleanly on shutdown.
 */

/**
 * Creates a sliding-window rate limiter.
 *
 * Algorithm (per client IP)
 * ─────────────────────────
 * A Map stores an ordered array of accepted request timestamps (ms) per IP.
 * On every incoming request:
 *   1. Prune timestamps older than (now − windowMs) from the front of the array.
 *      (Entries are always appended so the array stays chronologically sorted,
 *      making pruning a simple front-splice — O(k) where k = pruned count.)
 *   2. If remaining count >= maxRequests → reject 429.
 *   3. Otherwise → append `now`, write rate-limit headers, call next().
 *
 * A periodic sweep (every 60 s) deletes Map entries whose newest timestamp has
 * also slid out of the window, preventing unbounded memory growth for clients
 * that go quiet.
 *
 * @param  {RateLimiterOptions} [options={}]
 * @returns {RateLimiter}
 */
function createRateLimiter(options = {}) {

  // ── Option validation / defaults ──────────────────────────────────────────
  const windowMs = (typeof options.windowMs === 'number' && options.windowMs > 0)
    ? options.windowMs
    : 60_000;                          // default: 1 minute

  const maxRequests = (typeof options.maxRequests === 'number' && options.maxRequests > 0)
    ? Math.floor(options.maxRequests)
    : 100;                             // default: 100 req / window

  // ── Per-IP timestamp store ────────────────────────────────────────────────
  // Map<ip: string, timestamps: number[]>
  // Each value is a chronologically ordered list of *accepted* request times.
  const store = new Map();

  // ── Background cleanup ────────────────────────────────────────────────────
  // Runs every 60 s and evicts entries for IPs with no activity inside the
  // current window, preventing the Map from growing without bound.
  const CLEANUP_MS = 60_000;

  const cleanupTimer = setInterval(() => {
    const cutoff = Date.now() - windowMs;

    for (const [ip, timestamps] of store) {
      // The array is sorted ascending; the last element is the most recent hit.
      // If even the most recent request is older than the window, the whole
      // entry is stale and can be removed.
      if (timestamps.length === 0 || timestamps[timestamps.length - 1] <= cutoff) {
        store.delete(ip);
      }
    }
  }, CLEANUP_MS);

  // unref() lets the process exit naturally without needing an explicit close()
  // call in simple scripts, while still allowing close() for explicit teardown.
  cleanupTimer.unref();

  // ── Middleware ────────────────────────────────────────────────────────────
  /**
   * @param {import('express').Request}       req
   * @param {import('express').Response}      res
   * @param {import('express').NextFunction}  next
   */
  function middleware(req, res, next) {
    const ip  = req.ip ?? req.socket?.remoteAddress ?? 'unknown';
    const now = Date.now();
    const windowStart = now - windowMs;   // timestamps <= this are expired

    // Fetch or initialise the timestamp list for this IP.
    let timestamps = store.get(ip);
    if (!timestamps) {
      timestamps = [];
      store.set(ip, timestamps);
    }

    // ── 1. Prune expired timestamps ────────────────────────────────────────
    // Walk from the front (oldest) until we reach a timestamp still inside the
    // window, then splice everything before that index out in one shot.
    let pruneCount = 0;
    while (pruneCount < timestamps.length && timestamps[pruneCount] <= windowStart) {
      pruneCount++;
    }
    if (pruneCount > 0) {
      timestamps.splice(0, pruneCount);
    }

    // ── 2. Gate check ──────────────────────────────────────────────────────
    if (timestamps.length >= maxRequests) {
      // timestamps[0] is the oldest hit still in the window.
      // The client must wait until it slides out before a slot opens.
      const retryAfterMs  = timestamps[0] + windowMs - now;
      const retryAfterSec = Math.ceil(retryAfterMs / 1000);

      res.set('Retry-After', String(retryAfterSec));

      return res.status(429).json({
        error:      'Rate limit exceeded',
        retryAfter: retryAfterSec,
      });
    }

    // ── 3. Allow the request ───────────────────────────────────────────────
    timestamps.push(now);

    // X-RateLimit-Reset: the epoch second when the *oldest* entry in the
    // window (timestamps[0], which was just pushed if the list was empty)
    // will slide out and free up a slot.
    const resetEpochSec = Math.ceil((timestamps[0] + windowMs) / 1000);

    res.set({
      'X-RateLimit-Limit':     String(maxRequests),
      'X-RateLimit-Remaining': String(maxRequests - timestamps.length),
      'X-RateLimit-Reset':     String(resetEpochSec),
    });

    return next();
  }

  // ── close() ───────────────────────────────────────────────────────────────
  /**
   * Stops the background cleanup interval.
   * Call this during graceful shutdown so the event loop can drain.
   */
  function close() {
    clearInterval(cleanupTimer);
  }

  return { middleware, close };
}

module.exports = { createRateLimiter };
```

