/**
 * Sliding Window Rate Limiter Middleware for Express.js
 *
 * TRUE sliding window implementation (not fixed window / token bucket approximation).
 *
 * Each request's timestamp is tracked per client IP. On every request we:
 *   1. Prune timestamps older than (now - windowMs)
 *   2. Count remaining timestamps in the current window
 *   3. Reject if count >= maxRequests, otherwise record the new timestamp
 *
 * This produces a genuinely sliding enforcement window that moves continuously
 * with wall-clock time rather than resetting on fixed calendar boundaries.
 *
 * IMPORTANT NOTE ABOUT req.ip BEHIND PROXIES:
 *   - Express `req.ip` (and `req.ips`) only trust the `X-Forwarded-For` / `X-Real-IP`
 *     headers when you have explicitly enabled proxy trust:
 *       app.set('trust proxy', true);           // trust first hop
 *       app.set('trust proxy', 'loopback, 10.0.0.0/8'); // more specific
 *   - If you do NOT set trust proxy, req.ip will be the direct socket address
 *     (the load balancer / reverse proxy IP), causing all clients to share one bucket.
 *   - Always configure trust proxy correctly in production when running behind
 *     Nginx, Cloudflare, AWS ALB, etc. See Express docs for "trust proxy" settings.
 */

function createRateLimiter(options = {}) {
  const windowMs = Number.isFinite(options.windowMs) && options.windowMs > 0
    ? options.windowMs
    : 60000;

  const maxRequests = Number.isFinite(options.maxRequests) && options.maxRequests > 0
    ? Math.floor(options.maxRequests)
    : 100;

  // In-memory store: Map<ip, number[]>  (array of request timestamps, kept sorted ascending)
  const requests = new Map();

  // Periodic cleanup: every 60 seconds, drop IPs that have no timestamps left in the current window.
  // This prevents unbounded memory growth from IPs that make a few requests then go away.
  // We use .unref() so the timer does not keep the Node.js process alive when it would otherwise exit.
  const cleanupInterval = setInterval(() => {
    const now = Date.now();
    const cutoff = now - windowMs;

    for (const [ip, timestamps] of requests.entries()) {
      // Filter to only timestamps still inside the window
      const recent = timestamps.filter(ts => ts > cutoff);

      if (recent.length === 0) {
        requests.delete(ip);
      } else if (recent.length !== timestamps.length) {
        requests.set(ip, recent);
      }
    }
  }, 60000);

  // Allow the cleanup timer to be garbage-collected if nothing else keeps the process running.
  if (typeof cleanupInterval.unref === 'function') {
    cleanupInterval.unref();
  }

  /**
   * The actual Express middleware.
   */
  const middleware = (req, res, next) => {
    // Determine client identifier.
    // See the module-level comment above about req.ip and trust proxy.
    const ip = (req.ip || req.connection?.remoteAddress || req.socket?.remoteAddress || 'unknown').toString();

    const now = Date.now();
    const cutoff = now - windowMs;

    // Retrieve (or initialize) this IP's timestamp list and prune old entries.
    let timestamps = requests.get(ip) || [];
    if (timestamps.length > 0) {
      timestamps = timestamps.filter(ts => ts > cutoff);
    }

    // --- DECISION ---
    if (timestamps.length >= maxRequests) {
      // Compute when the oldest request will fall out of the window.
      const oldest = timestamps[0];
      const retryAfterMs = Math.max(0, oldest + windowMs - now);
      const retryAfter = Math.max(1, Math.ceil(retryAfterMs / 1000));

      res.set('Retry-After', String(retryAfter));
      res.set('X-RateLimit-Limit', String(maxRequests));
      res.set('X-RateLimit-Remaining', '0');
      // Reset is the time (epoch seconds) when the current oldest request expires.
      res.set('X-RateLimit-Reset', String(Math.ceil((oldest + windowMs) / 1000)));

      return res.status(429).json({
        error: 'Rate limit exceeded',
        retryAfter
      });
    }

    // --- ALLOWED: record the request and continue ---
    timestamps.push(now);
    // No need to re-sort: because we always append a newer timestamp and previously
    // pruned from the front, the array remains sorted ascending.
    requests.set(ip, timestamps);

    // Standard rate-limit response headers (common convention)
    res.set('X-RateLimit-Limit', String(maxRequests));
    res.set('X-RateLimit-Remaining', String(maxRequests - timestamps.length));

    // X-RateLimit-Reset: epoch seconds when the *oldest* request in the current window expires.
    // After that moment the client will have one additional slot.
    const resetEpochSeconds = Math.ceil((timestamps[0] + windowMs) / 1000);
    res.set('X-RateLimit-Reset', String(resetEpochSeconds));

    next();
  };

